const e=JSON.parse(`[{"id":1,"section":"A","theme":"Daily activities","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne boit du café","image_prompt":"A person drinking coffee at a kitchen table, morning light"},{"id":"B","text":"Une personne lit un journal","image_prompt":"A person reading a newspaper on a sofa, relaxed posture"},{"id":"C","text":"Une personne prend le métro","image_prompt":"A person entering a subway train, urban setting"},{"id":"D","text":"Une personne achète des légumes","image_prompt":"A person buying vegetables at a market stall"}],"correct":0,"transcript_fr":"Chaque matin, je commence ma journée avec une bonne tasse de café chaud avant de partir au travail.","transcript_en":"Every morning, I start my day with a good cup of hot coffee before leaving for work.","points":[{"point":1,"male_lines":["Chaque matin, je commence ma journée avec une bonne tasse de café chaud avant de partir au travail."],"female_lines":[]}]},{"id":2,"section":"A","theme":"Transportation","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une voiture rouge sur l'autoroute","image_prompt":"A red car driving on a highway, traffic visible"},{"id":"B","text":"Un autobus scolaire arrêté","image_prompt":"A yellow school bus stopped at a corner, children nearby"},{"id":"C","text":"Un vélo garé devant un magasin","image_prompt":"A bicycle parked in front of a storefront"},{"id":"D","text":"Un train entrant en gare","image_prompt":"A train arriving at a station platform, passengers waiting"}],"correct":2,"transcript_fr":"J'ai décidé de me déplacer en vélo pour aller faire mes courses au centre-ville.","transcript_en":"I decided to get around by bicycle to go do my shopping downtown.","points":[{"point":1,"male_lines":["J'ai décidé de me déplacer en vélo pour aller faire mes courses au centre-ville."],"female_lines":[]}]},{"id":3,"section":"A","theme":"Food","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une pizza sur une table","image_prompt":"A pizza on a wooden table, steam rising"},{"id":"B","text":"Un sandwich triangle emballé","image_prompt":"A triangular wrapped sandwich, convenience store style"},{"id":"C","text":"Un bol de soupe chaude","image_prompt":"A bowl of hot soup with vegetables, steam visible"},{"id":"D","text":"Une assiette de pâtes","image_prompt":"A plate of spaghetti with tomato sauce and basil"}],"correct":3,"transcript_fr":"Ce soir, je vais préparer des pâtes avec une sauce maison pour toute la famille.","transcript_en":"Tonight, I'm going to prepare pasta with a homemade sauce for the whole family.","points":[{"point":1,"male_lines":["Ce soir, je vais préparer des pâtes avec une sauce maison pour toute la famille."],"female_lines":[]}]},{"id":4,"section":"A","theme":"Weather","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un parapluie sous la pluie","image_prompt":"An umbrella in heavy rain, person walking"},{"id":"B","text":"Un enfant jouant dans la neige","image_prompt":"A child building a snowman, winter scene"},{"id":"C","text":"Des gens à la plage sous le soleil","image_prompt":"People sunbathing on a beach, bright sunny day"},{"id":"D","text":"Des feuilles tombant des arbres","image_prompt":"Autumn leaves falling from trees, orange and red colors"}],"correct":1,"transcript_fr":"Il neige tellement fort aujourd'hui que les enfants peuvent faire un bonhomme de neige.","transcript_en":"It's snowing so hard today that the children can build a snowman.","points":[{"point":1,"male_lines":["Il neige tellement fort aujourd'hui que les enfants peuvent faire un bonhomme de neige."],"female_lines":[]}]},{"id":5,"section":"A","theme":"Work","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un ordinateur portable ouvert","image_prompt":"A laptop open on a desk, coffee cup nearby"},{"id":"B","text":"Un homme en costume parlant au téléphone","image_prompt":"A businessman in suit talking on phone, office background"},{"id":"C","text":"Une réunion autour d'une table","image_prompt":"A business meeting around a conference table, charts visible"},{"id":"D","text":"Une personne écrivant sur un tableau blanc","image_prompt":"A person writing on a whiteboard with markers"}],"correct":1,"transcript_fr":"Je dois appeler mon client urgent pour finaliser le contrat avant ce soir.","transcript_en":"I must call my urgent client to finalize the contract before tonight.","points":[{"point":1,"male_lines":["Je dois appeler mon client urgent pour finaliser le contrat avant ce soir."],"female_lines":[]}]},{"id":6,"section":"A","theme":"Shopping","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un panier d'épicerie plein","image_prompt":"A full grocery basket with fruits and vegetables"},{"id":"B","text":"Une personne essayant des chaussures","image_prompt":"A person trying on shoes in a shoe store, mirror visible"},{"id":"C","text":"Un caissier scannant des articles","image_prompt":"A cashier scanning items at a checkout counter"},{"id":"D","text":"Des vêtements sur des cintres","image_prompt":"Clothes hanging on racks in a clothing store"}],"correct":3,"transcript_fr":"Je cherche une nouvelle chemise pour mon entretien d'embauche la semaine prochaine.","transcript_en":"I'm looking for a new shirt for my job interview next week.","points":[{"point":1,"male_lines":["Je cherche une nouvelle chemise pour mon entretien d'embauche la semaine prochaine."],"female_lines":[]}]},{"id":7,"section":"B","theme":"Restaurant","question":"Où se déroule cette conversation ?","options":[{"id":"A","text":"Dans une bibliothèque","image_prompt":""},{"id":"B","text":"Dans un restaurant","image_prompt":""},{"id":"C","text":"Dans un magasin de vêtements","image_prompt":""},{"id":"D","text":"Dans une banque","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Bonjour, j'aimerais réserver une table pour deux personnes ce soir. Femme : Bien sûr monsieur, à quelle heure souhaitez-vous venir ? Homme : Vers 19h30 si possible. Femme : Parfait, j'ai une table disponible près de la fenêtre.","transcript_en":"Man : Hello, I would like to reserve a table for two people this evening. Woman : Of course sir, what time would you like to come? Man : Around 7:30 PM if possible. Woman : Perfect, I have a table available near the window.","points":[{"point":1,"male_lines":["Bonjour, j'aimerais réserver une table pour deux personnes ce soir.","Vers 19h30 si possible."],"female_lines":["Bien sûr monsieur, à quelle heure souhaitez-vous venir ?","Parfait, j'ai une table disponible près de la fenêtre."]},{"point":2,"male_lines":["C'est parfait, merci beaucoup.","Est-ce qu'il y a un menu végétarien ?"],"female_lines":["Je vous en prie monsieur.","Oui, nous avons plusieurs options végétariennes."]},{"point":3,"male_lines":["Excellent, ma femme va être contente.","Puis-je avoir votre nom pour la réservation ?"],"female_lines":["Je suis ravie de l'entendre.","Oui, c'est Martin, avec un t."]},{"point":4,"male_lines":["Merci, à ce soir alors.","Au revoir."],"female_lines":["À ce soir monsieur Martin.","Au revoir et bonne journée."]}]},{"id":8,"section":"B","theme":"Post office","question":"Que veut faire le client ?","options":[{"id":"A","text":"Envoyer un colis","image_prompt":""},{"id":"B","text":"Acheter des timbres","image_prompt":""},{"id":"C","text":"Ouvrir un compte bancaire","image_prompt":""},{"id":"D","text":"Retirer de l'argent","image_prompt":""}],"correct":0,"transcript_fr":"Homme : Bonjour madame, j'aimerais envoyer ce colis au Canada. Femme : D'accord, est-ce que c'est fragile ? Homme : Non, ce sont des livres. Femme : Très bien, ça fera douze dollars cinquante.","transcript_en":"Man : Hello madam, I would like to send this package to Canada. Woman : Okay, is it fragile? Man : No, these are books. Woman : Very well, that will be twelve dollars fifty.","points":[{"point":1,"male_lines":["Bonjour madame, j'aimerais envoyer ce colis au Canada.","Non, ce sont des livres."],"female_lines":["D'accord, est-ce que c'est fragile ?","Très bien, ça fera douze dollars cinquante."]},{"point":2,"male_lines":["C'est un peu cher, non ?","Combien de temps ça prend ?"],"female_lines":["C'est le tarif international monsieur.","Environ cinq jours ouvrables."]},{"point":3,"male_lines":["D'accord, ça me convient.","Je peux payer par carte ?"],"female_lines":["Parfait, je prépare l'étiquette.","Oui, bien sûr, la machine est là."]},{"point":4,"male_lines":["Voilà, merci beaucoup.","Bonne journée à vous."],"female_lines":["Merci monsieur, voici votre reçu.","Bonne journée également."]}]},{"id":9,"section":"B","theme":"Doctor","question":"Quel est le problème du patient ?","options":[{"id":"A","text":"Il a mal à la tête","image_prompt":""},{"id":"B","text":"Il a mal au dos","image_prompt":""},{"id":"C","text":"Il a mal à la gorge","image_prompt":""},{"id":"D","text":"Il a mal au ventre","image_prompt":""}],"correct":2,"transcript_fr":"Femme : Docteur, j'ai mal à la gorge depuis trois jours. Homme : Voyons voir, ouvrez la bouche s'il vous plaît. Femme : Ahh... Homme : Oui, c'est rouge, vous avez une infection.","transcript_en":"Woman : Doctor, I've had a sore throat for three days. Man : Let's see, open your mouth please. Woman : Ahh... Man : Yes, it's red, you have an infection.","points":[{"point":1,"male_lines":["Voyons voir, ouvrez la bouche s'il vous plaît.","Oui, c'est rouge, vous avez une infection."],"female_lines":["Docteur, j'ai mal à la gorge depuis trois jours.","Ahh..."]},{"point":2,"male_lines":["Je vais vous prescrire des antibiotiques.","Prenez-les pendant une semaine."],"female_lines":["Est-ce que c'est grave docteur ?","D'accord, je vais suivre le traitement."]},{"point":3,"male_lines":["Non, c'est bénin, ne vous inquiétez pas.","Buvez beaucoup d'eau aussi."],"female_lines":["Merci docteur, je suis rassurée.","Oui, je vais faire attention."]},{"point":4,"male_lines":["Revenez me voir dans une semaine.","Au revoir madame."],"female_lines":["Très bien, à la semaine prochaine.","Au revoir et merci encore."]}]},{"id":10,"section":"B","theme":"Bank","question":"Que demande la cliente ?","options":[{"id":"A","text":"Un prêt immobilier","image_prompt":""},{"id":"B","text":"Une carte de crédit","image_prompt":""},{"id":"C","text":"Un relevé de compte","image_prompt":""},{"id":"D","text":"Changer son code PIN","image_prompt":""}],"correct":3,"transcript_fr":"Femme : Bonjour, j'aimerais changer mon code PIN s'il vous plaît. Homme : Bien sûr madame, avez-vous votre carte avec vous ? Femme : Oui, la voici. Homme : Merci, je vais vous aider à créer un nouveau code.","transcript_en":"Woman : Hello, I would like to change my PIN code please. Man : Of course madam, do you have your card with you? Woman : Yes, here it is. Man : Thank you, I will help you create a new code.","points":[{"point":1,"male_lines":["Bien sûr madame, avez-vous votre carte avec vous ?","Merci, je vais vous aider à créer un nouveau code."],"female_lines":["Bonjour, j'aimerais changer mon code PIN s'il vous plaît.","Oui, la voici."]},{"point":2,"male_lines":["Entrez votre nouveau code à quatre chiffres.","Confirmez-le une deuxième fois."],"female_lines":["D'accord, j'entre le code maintenant.","C'est fait, c'est le même code."]},{"point":3,"male_lines":["Parfait, le changement est effectué.","Votre carte est activée."],"female_lines":["Excellent, c'était rapide.","Merci beaucoup monsieur."]},{"point":4,"male_lines":["Je vous en prie madame.","Passez une bonne journée."],"female_lines":["Au revoir.","À bientôt."]}]},{"id":11,"section":"C","theme":"Airport announcement","question":"Quel est le sujet principal de cette annonce ?","options":[{"id":"A","text":"Un retard de vol","image_prompt":""},{"id":"B","text":"Un changement de porte d'embarquement","image_prompt":""},{"id":"C","text":"Une annulation de vol","image_prompt":""},{"id":"D","text":"Un appel pour un passager","image_prompt":""}],"correct":1,"transcript_fr":"Mesdames et messieurs, nous vous informons que le vol AC457 à destination de Toronto subit un changement de porte d'embarquement. Le vol partira maintenant de la porte vingt-quatre au lieu de la porte douze. Nous vous prions de vous rendre à la porte vingt-quatre immédiatement. L'embarquement commence dans dix minutes. Merci de votre attention et bon voyage avec Air Canada.","transcript_en":"Ladies and gentlemen, we inform you that flight AC457 to Toronto is undergoing a gate change. The flight will now depart from gate twenty-four instead of gate twelve. We ask you to proceed to gate twenty-four immediately. Boarding begins in ten minutes. Thank you for your attention and have a pleasant flight with Air Canada.","points":[{"point":1,"male_lines":["Mesdames et messieurs, nous vous informons que le vol AC457 à destination de Toronto subit un changement de porte d'embarquement.","Le vol partira maintenant de la porte vingt-quatre au lieu de la porte douze."],"female_lines":[]},{"point":2,"male_lines":["Nous vous prions de vous rendre à la porte vingt-quatre immédiatement.","L'embarquement commence dans dix minutes."],"female_lines":[]},{"point":3,"male_lines":["Merci de votre attention et bon voyage avec Air Canada.",""],"female_lines":[]}]},{"id":12,"section":"C","theme":"Supermarket announcement","question":"Que demande cette annonce ?","options":[{"id":"A","text":"De fermer le magasin","image_prompt":""},{"id":"B","text":"De venir à la caisse numéro cinq","image_prompt":""},{"id":"C","text":"De signaler une promotion","image_prompt":""},{"id":"D","text":"De retrouver un enfant perdu","image_prompt":""}],"correct":3,"transcript_fr":"Attention clients, nous recherchons un jeune garçon nommé Thomas, âgé de cinq ans, portant un manteau bleu et un bonnet rouge. Sa mère l'attend au service client près de l'entrée principale. Si vous voyez cet enfant, veuillez l'accompagner immédiatement au service client ou contacter un employé. Merci pour votre aide et votre compréhension.","transcript_en":"Attention customers, we are looking for a young boy named Thomas, five years old, wearing a blue coat and a red hat. His mother is waiting at the customer service near the main entrance. If you see this child, please accompany him immediately to customer service or contact an employee. Thank you for your help and understanding.","points":[{"point":1,"male_lines":["Attention clients, nous recherchons un jeune garçon nommé Thomas, âgé de cinq ans, portant un manteau bleu et un bonnet rouge.","Sa mère l'attend au service client près de l'entrée principale."],"female_lines":[]},{"point":2,"male_lines":["Si vous voyez cet enfant, veuillez l'accompagner immédiatement au service client ou contacter un employé.","Merci pour votre aide et votre compréhension."],"female_lines":[]}]},{"id":13,"section":"C","theme":"Train station announcement","question":"Quelle information donne cette annonce ?","options":[{"id":"A","text":"Le train est en retard","image_prompt":""},{"id":"B","text":"Le train est supprimé","image_prompt":""},{"id":"C","text":"Le train arrive à l'heure","image_prompt":""},{"id":"D","text":"Le train est complet","image_prompt":""}],"correct":0,"transcript_fr":"Voyageurs du train Intercity quarante-deux à destination de Québec, nous vous informons que votre train subit un retard de quinze minutes en raison de travaux sur la voie. Le départ est maintenant prévu à quatorze heures trente au lieu de quatorze heures quinze. Veuillez rester dans la salle d'attente jusqu'à l'annonce de l'arrivée du train sur le quai numéro trois. Nous vous prions d'accepter nos excuses pour ce désagrément.","transcript_en":"Passengers of Intercity train forty-two to Quebec, we inform you that your train is delayed by fifteen minutes due to track work. Departure is now scheduled for two thirty PM instead of two fifteen PM. Please remain in the waiting room until the announcement of the train's arrival on platform number three. We ask you to accept our apologies for this inconvenience.","points":[{"point":1,"male_lines":["Voyageurs du train Intercity quarante-deux à destination de Québec, nous vous informons que votre train subit un retard de quinze minutes en raison de travaux sur la voie.","Le départ est maintenant prévu à quatorze heures trente au lieu de quatorze heures quinze."],"female_lines":[]},{"point":2,"male_lines":["Veuillez rester dans la salle d'attente jusqu'à l'annonce de l'arrivée du train sur le quai numéro trois.","Nous vous prions d'accepter nos excuses pour ce désagrément."],"female_lines":[]}]},{"id":14,"section":"C","theme":"Weather alert","question":"Quel type d'alerte est annoncé ?","options":[{"id":"A","text":"Une alerte canicule","image_prompt":""},{"id":"B","text":"Une alerte tempête de neige","image_prompt":""},{"id":"C","text":"Une alerte pluie verglaçante","image_prompt":""},{"id":"D","text":"Une alerte orages","image_prompt":""}],"correct":1,"transcript_fr":"Alerte météo pour la région de Montréal et ses environs. Une tempête de neige importante est prévue pour cette nuit et demain matin. Les accumulations pourraient atteindre vingt-cinq centimètres. Les routes seront très glissantes et la visibilité sera réduite. Évitez les déplacements non essentiels. Si vous devez sortir, équipez-vous de pneus d'hiver et conduisez prudemment. Restez à l'écoute des mises à jour.","transcript_en":"Weather alert for the Montreal region and surrounding areas. A significant snowstorm is expected tonight and tomorrow morning. Accumulations could reach twenty-five centimeters. Roads will be very slippery and visibility will be reduced. Avoid non-essential travel. If you must go out, equip yourself with winter tires and drive carefully. Stay tuned for updates.","points":[{"point":1,"male_lines":["Alerte météo pour la région de Montréal et ses environs.","Une tempête de neige importante est prévue pour cette nuit et demain matin."],"female_lines":[]},{"point":2,"male_lines":["Les accumulations pourraient atteindre vingt-cinq centimètres.","Les routes seront très glissantes et la visibilité sera réduite."],"female_lines":[]},{"point":3,"male_lines":["Évitez les déplacements non essentiels.","Si vous devez sortir, équipez-vous de pneus d'hiver et conduisez prudemment."],"female_lines":[]},{"point":4,"male_lines":["Restez à l'écoute des mises à jour.",""],"female_lines":[]}]},{"id":15,"section":"C","theme":"School announcement","question":"Qu'est-ce qui est annoncé ?","options":[{"id":"A","text":"Une fermeture de l'école","image_prompt":""},{"id":"B","text":"Une réunion des parents","image_prompt":""},{"id":"C","text":"Une excursion scolaire","image_prompt":""},{"id":"D","text":"Un spectacle de fin d'année","image_prompt":""}],"correct":2,"transcript_fr":"Chers parents, nous vous informons que les élèves de la classe de madame Tremblay partiront en excursion au musée des sciences naturelles le prochain mardi quinze mai. Le départ est prévu à huit heures trente précises. Veuillez prévoir un pique-nique pour votre enfant et s'assurer qu'il ait des vêtements confortables. Les bus reviendront à l'école vers seize heures. Merci de retourner l'autorisation signée avant vendredi.","transcript_en":"Dear parents, we inform you that the students of Mrs. Tremblay's class will go on a field trip to the natural science museum next Tuesday, May fifteenth. Departure is scheduled for eight thirty sharp. Please provide a picnic lunch for your child and ensure they have comfortable clothing. The buses will return to school around four PM. Please return the signed permission slip before Friday.","points":[{"point":1,"male_lines":["Chers parents, nous vous informons que les élèves de la classe de madame Tremblay partiront en excursion au musée des sciences naturelles le prochain mardi quinze mai.","Le départ est prévu à huit heures trente précises."],"female_lines":[]},{"point":2,"male_lines":["Veuillez prévoir un pique-nique pour votre enfant et s'assurer qu'il ait des vêtements confortables.","Les bus reviendront à l'école vers seize heures."],"female_lines":[]},{"point":3,"male_lines":["Merci de retourner l'autorisation signée avant vendredi.",""],"female_lines":[]}]},{"id":16,"section":"C","theme":"Public transport announcement","question":"Quel changement est annoncé ?","options":[{"id":"A","text":"Une grève des conducteurs","image_prompt":""},{"id":"B","text":"Une interruption de service","image_prompt":""},{"id":"C","text":"Une modification d'horaire","image_prompt":""},{"id":"D","text":"Une nouvelle ligne de métro","image_prompt":""}],"correct":2,"transcript_fr":"Chers usagers, la ligne de métro verte subira des modifications d'horaire à partir du prochain lundi. Les trains circuleront toutes les huit minutes aux heures de pointe au lieu de toutes les cinq minutes. Aux heures creuses, l'attente sera de douze minutes. Ces changements sont temporaires et dureront trois semaines pour permettre des travaux de maintenance. Nous vous remercions de votre patience et de votre compréhension durant cette période.","transcript_en":"Dear users, the green metro line will undergo schedule changes starting next Monday. Trains will run every eight minutes during rush hour instead of every five minutes. During off-peak hours, the wait will be twelve minutes. These changes are temporary and will last three weeks to allow for maintenance work. We thank you for your patience and understanding during this period.","points":[{"point":1,"male_lines":["Chers usagers, la ligne de métro verte subira des modifications d'horaire à partir du prochain lundi.","Les trains circuleront toutes les huit minutes aux heures de pointe au lieu de toutes les cinq minutes."],"female_lines":[]},{"point":2,"male_lines":["Aux heures creuses, l'attente sera de douze minutes.","Ces changements sont temporaires et dureront trois semaines pour permettre des travaux de maintenance."],"female_lines":[]},{"point":3,"male_lines":["Nous vous remercions de votre patience et de votre compréhension durant cette période.",""],"female_lines":[]}]},{"id":17,"section":"D","theme":"Job interview","question":"Quelle est l'intention du recruteur ?","options":[{"id":"A","text":"Refuser la candidature","image_prompt":""},{"id":"B","text":"Proposer un entretien","image_prompt":""},{"id":"C","text":"Demander des références","image_prompt":""},{"id":"D","text":"Négocier le salaire","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Merci d'être venu monsieur, j'ai bien étudié votre CV. Femme : Je vous remercie de me recevoir, je suis très intéressé par ce poste. Homme : Votre profil correspond à ce que nous recherchons. Femme : C'est une excellente nouvelle, quand puis-je commencer ?","transcript_en":"Man : Thank you for coming sir, I have carefully studied your CV. Woman : Thank you for receiving me, I am very interested in this position. Man : Your profile matches what we are looking for. Woman : That's excellent news, when can I start?","points":[{"point":1,"male_lines":["Merci d'être venu monsieur, j'ai bien étudié votre CV.","Votre profil correspond à ce que nous recherchons."],"female_lines":["Je vous remercie de me recevoir, je suis très intéressé par ce poste.","C'est une excellente nouvelle, quand puis-je commencer ?"]},{"point":2,"male_lines":["Je peux vous proposer un entretien technique la semaine prochaine.","Ça vous convient mardi prochain ?"],"female_lines":["Oui, parfait, je suis disponible.","À quelle heure exactement ?"]},{"point":3,"male_lines":["Disons à dix heures du matin.","Apportez vos diplômes et références."],"female_lines":["D'accord, je serai là à l'heure.","Pas de problème, j'ai tout préparé."]},{"point":4,"male_lines":["Excellent, nous avons hâte de vous rencontrer.","Bonne journée monsieur."],"female_lines":["Merci beaucoup pour cette opportunité.","Au revoir et à mardi."]}]},{"id":18,"section":"D","theme":"Complaint","question":"Que veut la cliente ?","options":[{"id":"A","text":"Un remboursement","image_prompt":""},{"id":"B","text":"Un échange","image_prompt":""},{"id":"C","text":"Une réparation gratuite","image_prompt":""},{"id":"D","text":"Parler au directeur","image_prompt":""}],"correct":0,"transcript_fr":"Femme : Bonjour, j'ai acheté ce téléphone hier et il ne fonctionne déjà plus. Homme : Je suis désolé madame, quel est le problème exactement ? Femme : L'écran reste noir, il ne s'allume pas du tout. Homme : Je comprends, voulez-vous un échange ou un remboursement ?","transcript_en":"Woman : Hello, I bought this phone yesterday and it already doesn't work. Man : I'm sorry madam, what is the exact problem? Woman : The screen stays black, it doesn't turn on at all. Man : I understand, would you like an exchange or a refund?","points":[{"point":1,"male_lines":["Je suis désolé madame, quel est le problème exactement ?","Je comprends, voulez-vous un échange ou un remboursement ?"],"female_lines":["Bonjour, j'ai acheté ce téléphone hier et il ne fonctionne déjà plus.","L'écran reste noir, il ne s'allume pas du tout."]},{"point":2,"male_lines":["Je préfère le remboursement s'il vous plaît.","Le service après-vente m'a dit de venir ici."],"female_lines":["Très bien, je peux procéder au remboursement.","Avez-vous la carte de crédit utilisée pour l'achat ?"]},{"point":3,"male_lines":["Oui, la voici avec le reçu.","Le remboursement est immédiat ?"],"female_lines":["Parfait, je traite cela maintenant.","Oui, sous cinq jours ouvrables sur votre compte."]},{"point":4,"male_lines":["Merci pour votre aide.","Bonne journée."],"female_lines":["Je vous en prie madame.","Au revoir."]}]},{"id":19,"section":"D","theme":"Invitation","question":"Quelle est la réponse de la femme ?","options":[{"id":"A","text":"Elle accepte avec enthousiasme","image_prompt":""},{"id":"B","text":"Elle refuse poliment","image_prompt":""},{"id":"C","text":"Elle demande des précisions","image_prompt":""},{"id":"D","text":"Elle propose une autre date","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Ça te dirait d'aller au cinéma ce soir ? Il y a un nouveau film français. Femme : Merci beaucoup pour l'invitation, c'est gentil. Homme : Alors, tu viens ? Femme : Je suis désolée, mais j'ai déjà un rendez-vous ce soir.","transcript_en":"Man : Would you like to go to the movies tonight? There's a new French film. Woman : Thank you very much for the invitation, that's kind. Man : So, are you coming? Woman : I'm sorry, but I already have an appointment tonight.","points":[{"point":1,"male_lines":["Ça te dirait d'aller au cinéma ce soir ? Il y a un nouveau film français.","Alors, tu viens ?"],"female_lines":["Merci beaucoup pour l'invitation, c'est gentil.","Je suis désolée, mais j'ai déjà un rendez-vous ce soir."]},{"point":2,"male_lines":["Ah c'est dommage, une autre fois peut-être ?","Le film passe toute la semaine."],"female_lines":["Oui, peut-être ce week-end ?","Je serai plus disponible samedi."]},{"point":3,"male_lines":["Samedi soir me convient parfaitement.","On se retrouve à quelle heure ?"],"female_lines":["Disons à vingt heures devant le cinéma.","D'accord, c'est noté."]},{"point":4,"male_lines":["Parfait, à samedi alors.","Bonne journée."],"female_lines":["À samedi, merci encore.","Au revoir."]}]},{"id":20,"section":"D","theme":"Directions","question":"Que cherche l'homme ?","options":[{"id":"A","text":"La gare","image_prompt":""},{"id":"B","text":"L'hôtel de ville","image_prompt":""},{"id":"C","text":"La pharmacie","image_prompt":""},{"id":"D","text":"Le musée","image_prompt":""}],"correct":2,"transcript_fr":"Homme : Excusez-moi madame, pourriez-vous m'indiquer où se trouve la pharmacie la plus proche ? Femme : Bien sûr, continuez tout droit jusqu'au feu rouge. Homme : D'accord, et après ? Femme : Tournez à gauche, c'est juste après la boulangerie.","transcript_en":"Man : Excuse me madam, could you tell me where the nearest pharmacy is? Woman : Of course, continue straight ahead until the red light. Man : Okay, and then? Woman : Turn left, it's right after the bakery.","points":[{"point":1,"male_lines":["Excusez-moi madame, pourriez-vous m'indiquer où se trouve la pharmacie la plus proche ?","D'accord, et après ?"],"female_lines":["Bien sûr, continuez tout droit jusqu'au feu rouge.","Tournez à gauche, c'est juste après la boulangerie."]},{"point":2,"male_lines":["C'est à combien de minutes à pied ?","Je ne connais pas bien le quartier."],"female_lines":["Environ cinq minutes de marche.","C'est très facile à trouver."]},{"point":3,"male_lines":["Parfait, merci beaucoup pour votre aide.","La pharmacie est ouverte aujourd'hui ?"],"female_lines":["Je vous en prie.","Oui, jusqu'à dix-neuf heures."]},{"point":4,"male_lines":["Excellent, j'ai le temps alors.","Bonne journée madame."],"female_lines":["Bonne journée à vous aussi.","Au revoir."]}]},{"id":21,"section":"D","theme":"Restaurant order","question":"Que demande le client ?","options":[{"id":"A","text":"La carte des vins","image_prompt":""},{"id":"B","text":"L'addition","image_prompt":""},{"id":"C","text":"Un verre d'eau","image_prompt":""},{"id":"D","text":"Des renseignements sur un plat","image_prompt":""}],"correct":3,"transcript_fr":"Homme : Bonjour, j'aimerais savoir si le plat du jour contient des produits laitiers ? Femme : Oui monsieur, il y a de la crème dans la sauce. Homme : Je suis allergique au lactose, avez-vous une alternative ? Femme : Bien sûr, je peux préparer la sauce sans crème pour vous.","transcript_en":"Man : Hello, I would like to know if the daily special contains dairy products? Woman : Yes sir, there is cream in the sauce. Man : I'm allergic to lactose, do you have an alternative? Woman : Of course, I can prepare the sauce without cream for you.","points":[{"point":1,"male_lines":["Bonjour, j'aimerais savoir si le plat du jour contient des produits laitiers ?","Je suis allergique au lactose, avez-vous une alternative ?"],"female_lines":["Oui monsieur, il y a de la crème dans la sauce.","Bien sûr, je peux préparer la sauce sans crème pour vous."]},{"point":2,"male_lines":["Ce serait parfait, merci beaucoup.","Et pour le dessert, qu'est-ce que vous recommandez ?"],"female_lines":["Je vous en prie monsieur.","Nous avons une mousse au chocolat sans lactose."]},{"point":3,"male_lines":["Excellent choix, je vais prendre ça.","Puis-je aussi avoir un café sans lait ?"],"female_lines":["Très bien, je note.","Oui, nature ou avec une alternative végétale ?"]},{"point":4,"male_lines":["Nature s'il vous plaît.","Merci pour votre compréhension."],"female_lines":["Parfait, c'est noté.","Je vous en prie, bon appétit."]}]},{"id":22,"section":"D","theme":"Hotel check-in","question":"Quel problème rencontre le client ?","options":[{"id":"A","text":"Sa réservation est annulée","image_prompt":""},{"id":"B","text":"Sa chambre n'est pas prête","image_prompt":""},{"id":"C","text":"Il a oublié son passeport","image_prompt":""},{"id":"D","text":"Le prix a augmenté","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Bonjour, j'ai une réservation au nom de Dubois. Femme : Bienvenue monsieur Dubois, laissez-moi vérifier. Homme : Merci, j'espère que ma chambre est disponible. Femme : Je suis désolée, votre chambre n'est pas encore prête, il faut attendre trente minutes.","transcript_en":"Man : Hello, I have a reservation under the name Dubois. Woman : Welcome Mr. Dubois, let me check. Man : Thank you, I hope my room is available. Woman : I'm sorry, your room is not ready yet, you need to wait thirty minutes.","points":[{"point":1,"male_lines":["Bonjour, j'ai une réservation au nom de Dubois.","Merci, j'espère que ma chambre est disponible."],"female_lines":["Bienvenue monsieur Dubois, laissez-moi vérifier.","Je suis désolée, votre chambre n'est pas encore prête, il faut attendre trente minutes."]},{"point":2,"male_lines":["C'est embêtant, j'ai un rendez-vous dans une heure.","Puis-je déposer mes bagages en attendant ?"],"female_lines":["Je comprends monsieur, je suis vraiment désolée.","Bien sûr, je vais les stocker pour vous."]},{"point":3,"male_lines":["Merci, c'est gentil.","Y a-t-il un salon où je peux attendre ?"],"female_lines":["Je vous en prie.","Oui, au premier étage avec des boissons gratuites."]},{"point":4,"male_lines":["Parfait, je vais m'y installer.","Merci pour votre aide."],"female_lines":["Je vous appellerai quand la chambre sera prête.","Avec plaisir monsieur."]}]},{"id":23,"section":"E","theme":"Radio interview - Environment","question":"Quel est le sujet principal de l'interview ?","options":[{"id":"A","text":"Le réchauffement climatique","image_prompt":""},{"id":"B","text":"Le recyclage des déchets","image_prompt":""},{"id":"C","text":"L'agriculture biologique","image_prompt":""},{"id":"D","text":"Les énergies renouvelables","image_prompt":""}],"correct":3,"transcript_fr":"Présentateur : Aujourd'hui nous recevons madame Lefebvre, experte en énergies renouvelables. Invitée : Merci de m'accueillir. Présentateur : Pouvez-vous nous expliquer l'importance des énergies renouvelables au Québec ? Invitée : Absolument, le Québec possède un immense potentiel hydroélectrique.","transcript_en":"Host : Today we welcome Mrs. Lefebvre, expert in renewable energies. Guest : Thank you for having me. Host : Can you explain to us the importance of renewable energies in Quebec? Guest : Absolutely, Quebec has immense hydroelectric potential.","points":[{"point":1,"male_lines":["Aujourd'hui nous recevons madame Lefebvre, experte en énergies renouvelables.","Pouvez-vous nous expliquer l'importance des énergies renouvelables au Québec ?"],"female_lines":["Merci de m'accueillir.","Absolument, le Québec possède un immense potentiel hydroélectrique."]},{"point":2,"male_lines":["L'hydroélectricité représente quel pourcentage de notre production ?","Est-ce que le Québec exporte cette énergie ?"],"female_lines":["Environ quatre-vingt-dix-sept pour cent de notre électricité.","Oui, nous vendons le surplus aux États-Unis."]},{"point":3,"male_lines":["Quels autres types d'énergies renouvelables développons-nous ?","L'éolien est-il prometteur ?"],"female_lines":["Nous investissons dans l'éolien et la biomasse.","Très prometteur, surtout en Gaspésie."]},{"point":4,"male_lines":["Comment les citoyens peuvent-ils contribuer ?","Des conseils pour nos auditeurs ?"],"female_lines":["En réduisant leur consommation et en choisissant l'hybride.","Isoler bien leur maison, c'est essentiel."]}]},{"id":24,"section":"E","theme":"Radio interview - Health","question":"Quel conseil donne le médecin ?","options":[{"id":"A","text":"Faire du sport tous les jours","image_prompt":""},{"id":"B","text":"Dormir au moins huit heures","image_prompt":""},{"id":"C","text":"Manger cinq fruits et légumes","image_prompt":""},{"id":"D","text":"Boire beaucoup d'eau","image_prompt":""}],"correct":0,"transcript_fr":"Présentateur : Docteur Martin, quels sont vos conseils pour rester en bonne santé ? Invité : La première règle est de bouger quotidiennement. Présentateur : Même une petite activité suffit ? Invité : Oui, trente minutes de marche par jour changent beaucoup de choses.","transcript_en":"Host : Dr. Martin, what are your tips for staying healthy? Guest : The first rule is to move daily. Host : Even a small activity is enough? Guest : Yes, thirty minutes of walking per day changes many things.","points":[{"point":1,"male_lines":["Docteur Martin, quels sont vos conseils pour rester en bonne santé ?","Même une petite activité suffit ?"],"female_lines":["La première règle est de bouger quotidiennement.","Oui, trente minutes de marche par jour changent beaucoup de choses."]},{"point":2,"male_lines":["Quel type d'exercice recommandez-vous ?","La natation est-elle bonne ?"],"female_lines":["La marche rapide est excellente pour le cœur.","La natation est parfaite pour les articulations."]},{"point":3,"male_lines":["Faut-il aller à la salle de sport ?","Ou l'extérieur suffit ?"],"female_lines":["Pas obligatoire, l'extérieur est souvent mieux.","L'air frais amplifie les bienfaits."]},{"point":4,"male_lines":["Merci docteur pour ces conseils pratiques.","À bientôt sur nos ondes."],"female_lines":["Je vous en prie, prenez soin de vous.","Au revoir et bonne santé."]}]},{"id":25,"section":"E","theme":"Radio interview - Technology","question":"Quelle est l'opinion de l'invité sur les réseaux sociaux ?","options":[{"id":"A","text":"Ils sont dangereux pour les jeunes","image_prompt":""},{"id":"B","text":"Ils sont utiles pour la communication","image_prompt":""},{"id":"C","text":"Ils devraient être interdits","image_prompt":""},{"id":"D","text":"Ils n'ont aucun impact","image_prompt":""}],"correct":1,"transcript_fr":"Présentatrice : Monsieur Tremblay, que pensez-vous des réseaux sociaux ? Invité : Je les considère comme des outils de communication très puissants. Présentatrice : Malgré les critiques ? Invité : Oui, il faut simplement les utiliser avec discernement et modération.","transcript_en":"Host : Mr. Tremblay, what do you think of social networks? Guest : I consider them very powerful communication tools. Host : Despite the criticism? Guest : Yes, we simply need to use them with discernment and moderation.","points":[{"point":1,"male_lines":["Je les considère comme des outils de communication très puissants.","Oui, il faut simplement les utiliser avec discernement et modération."],"female_lines":["Monsieur Tremblay, que pensez-vous des réseaux sociaux ?","Malgré les critiques ?"]},{"point":2,"male_lines":["Ils permettent de rester connecté avec la famille éloignée.","C'est révolutionnaire pour les relations."],"female_lines":["Mais quid de la désinformation ?","Beaucoup de fake news circulent."]},{"point":3,"male_lines":["C'est vrai, il faut vérifier ses sources.","L'éducation aux médias est cruciale."],"female_lines":["Comment protéger les adolescents ?","Les parents sont démunis."]},{"point":4,"male_lines":["Le dialogue familial est essentiel.","Encadrer sans interdire."],"female_lines":["Merci pour cette analyse nuancée.","Au revoir monsieur."]}]},{"id":26,"section":"E","theme":"Radio interview - Culture","question":"Quel événement culturel est discuté ?","options":[{"id":"A","text":"Un festival de musique","image_prompt":""},{"id":"B","text":"Une exposition de peinture","image_prompt":""},{"id":"C","text":"Un spectacle de théâtre","image_prompt":""},{"id":"D","text":"Un marathon littéraire","image_prompt":""}],"correct":0,"transcript_fr":"Présentateur : Madame Roy, parlez-nous du festival de jazz de Montréal. Invitée : C'est le plus grand festival de jazz au monde. Présentateur : Quand a-t-il lieu cette année ? Invitée : Du vingt-huit juin au huit juillet, avec des artistes internationaux.","transcript_en":"Host : Mrs. Roy, tell us about the Montreal Jazz Festival. Guest : It's the largest jazz festival in the world. Host : When does it take place this year? Guest : From June twenty-eighth to July eighth, with international artists.","points":[{"point":1,"male_lines":["Madame Roy, parlez-nous du festival de jazz de Montréal.","Quand a-t-il lieu cette année ?"],"female_lines":["C'est le plus grand festival de jazz au monde.","Du vingt-huit juin au huit juillet, avec des artistes internationaux."]},{"point":2,"male_lines":["Quels sont les têtes d'affiche cette année ?","Des noms connus du grand public ?"],"female_lines":["Nous avons Herbie Hancock et Diana Krall.","Oui, et de nouveaux talents québécois."]},{"point":3,"male_lines":["Les concerts sont-ils payants ?","Où se déroulent-ils ?"],"female_lines":["Beaucoup sont gratuits en plein air.","Au centre-ville, sur plusieurs scènes."]},{"point":4,"male_lines":["Un événement à ne pas manquer.","Merci madame Roy."],"female_lines":["Venez nombreux, c'est magique.","Au revoir et bonne musique."]}]},{"id":27,"section":"F","theme":"Housing debate","question":"Quelle est l'opinion de la femme sur la colocation ?","options":[{"id":"A","text":"Elle la recommande pour économiser","image_prompt":""},{"id":"B","text":"Elle préfère vivre seule","image_prompt":""},{"id":"C","text":"Elle trouve que c'est trop cher","image_prompt":""},{"id":"D","text":"Elle n'a pas d'opinion","image_prompt":""}],"correct":0,"transcript_fr":"Homme : Tu penses quoi de la colocation à notre âge ? Femme : C'est une excellente solution pour économiser de l'argent. Homme : Mais tu perds en intimité, non ? Femme : C'est vrai, mais les avantages financiers compensent largement.","transcript_en":"Man : What do you think of shared housing at our age? Woman : It's an excellent solution to save money. Man : But you lose privacy, right? Woman : That's true, but the financial advantages largely compensate.","points":[{"point":1,"male_lines":["Tu penses quoi de la colocation à notre âge ?","Mais tu perds en intimité, non ?"],"female_lines":["C'est une excellente solution pour économiser de l'argent.","C'est vrai, mais les avantages financiers compensent largement."]},{"point":2,"male_lines":["Je partage un appartement depuis deux ans.","Ça me permet d'épargner chaque mois."],"female_lines":["Moi aussi, je mets cinq cents dollars de côté.","C'est considérable à Montréal."]},{"point":3,"male_lines":["Et comment tu trouves des colocataires ?","C'est difficile de trouver la bonne personne ?"],"female_lines":["J'utilise des sites spécialisés.","Il faut faire des entretiens, comme un job."]},{"point":4,"male_lines":["Tu as déjà eu des conflits ?","Comment tu les gères ?"],"female_lines":["Quelques disputes sur la vaisselle.","On établit des règles claires dès le départ."]}]},{"id":28,"section":"F","theme":"Work-life balance","question":"Que pense l'homme du télétravail ?","options":[{"id":"A","text":"Il est contre car c'est isolant","image_prompt":""},{"id":"B","text":"Il est pour car c'est pratique","image_prompt":""},{"id":"C","text":"Il pense que c'est moins productif","image_prompt":""},{"id":"D","text":"Il n'a pas d'expérience avec","image_prompt":""}],"correct":1,"transcript_fr":"Femme : Tu travailles encore de la maison cette semaine ? Homme : Oui, et franchement je trouve ça très pratique. Femme : Tu ne manques pas tes collègues ? Homme : Un peu, mais je gagne deux heures de transport chaque jour.","transcript_en":"Woman : Are you still working from home this week? Man : Yes, and frankly I find it very convenient. Woman : Don't you miss your colleagues? Man : A little, but I save two hours of commuting every day.","points":[{"point":1,"male_lines":["Oui, et franchement je trouve ça très pratique.","Un peu, mais je gagne deux heures de transport chaque jour."],"female_lines":["Tu travailles encore de la maison cette semaine ?","Tu ne manques pas tes collègues ?"]},{"point":2,"male_lines":["Je peux déjeuner avec ma famille.","Et finir plus tôt le soir."],"female_lines":["Moi je préfère la séparation vie pro et perso.","La maison c'est sacré."]},{"point":3,"male_lines":["Je comprends, mais le flexibilité est précieuse.","Surtout avec des enfants."],"female_lines":["C'est vrai pour les parents.","Moi je n'ai pas d'enfants."]},{"point":4,"male_lines":["Le mixte est probablement l'idéal.","Trois jours bureau, deux jours maison."],"female_lines":["Oui, c'est ce que propose mon entreprise.","Je vais essayer ce modèle."]}]},{"id":29,"section":"F","theme":"Education debate","question":"Quelle est la position de la femme sur les devoirs ?","options":[{"id":"A","text":"Elle veut les supprimer","image_prompt":""},{"id":"B","text":"Elle veut les maintenir","image_prompt":""},{"id":"C","text":"Elle propose de les réduire","image_prompt":""},{"id":"D","text":"Elle n'a pas d'opinion","image_prompt":""}],"correct":2,"transcript_fr":"Homme : Les devoirs devraient être interdits selon toi ? Femme : Pas interdits, mais réduits significativement. Homme : Pourquoi cette nuance ? Femme : Parce que les enfants ont besoin de temps libre pour se développer.","transcript_en":"Man : Should homework be banned according to you? Woman : Not banned, but significantly reduced. Man : Why this nuance? Woman : Because children need free time to develop.","points":[{"point":1,"male_lines":["Les devoirs devraient être interdits selon toi ?","Pourquoi cette nuance ?"],"female_lines":["Pas interdits, mais réduits significativement.","Parce que les enfants ont besoin de temps libre pour se développer."]},{"point":2,"male_lines":["Mais l'école est faite pour apprendre.","La maison doit continuer le travail ?"],"female_lines":["Non, la maison est pour la famille.","Et pour les activités extrascolaires."]},{"point":3,"male_lines":["Mon fils passe deux heures sur ses devoirs.","C'est trop pour un primaire."],"female_lines":["Exactement, trente minutes maximum.","Après c'est contre-productif."]},{"point":4,"male_lines":["Tu as parlé à l'enseignante ?","Quelle est sa réaction ?"],"female_lines":["Elle est d'accord en fait.","Elle subit des directives du ministère."]}]},{"id":30,"section":"F","theme":"Immigration discussion","question":"Quel argument utilise l'homme ?","options":[{"id":"A","text":"Les immigrants prennent les emplois","image_prompt":""},{"id":"B","text":"Les immigrants enrichissent la culture","image_prompt":""},{"id":"C","text":"Il faut fermer les frontières","image_prompt":""},{"id":"D","text":"L'immigration coûte trop cher","image_prompt":""}],"correct":1,"transcript_fr":"Femme : Que penses-tu de la politique d'immigration actuelle ? Homme : Je pense que les immigrants enrichissent notre culture. Femme : Mais certains disent qu'il y a trop d'immigrants. Homme : C'est un mythe, nous avons besoin de main-d'œuvre qualifiée.","transcript_en":"Woman : What do you think of the current immigration policy? Man : I think immigrants enrich our culture. Woman : But some say there are too many immigrants. Man : That's a myth, we need qualified workforce.","points":[{"point":1,"male_lines":["Je pense que les immigrants enrichissent notre culture.","C'est un mythe, nous avons besoin de main-d'œuvre qualifiée."],"female_lines":["Que penses-tu de la politique d'immigration actuelle ?","Mais certains disent qu'il y a trop d'immigrants."]},{"point":2,"male_lines":["Mon entreprise embauche des ingénieurs étrangers.","On ne trouve pas assez de candidats locaux."],"female_lines":["Dans quel domaine ?","La tech manque de personnel ?"]},{"point":3,"male_lines":["En intelligence artificielle surtout.","Les Québécois forment aussi, mais ça prend du temps."],"female_lines":["Et l'intégration linguistique ?","Le français est respecté ?"]},{"point":4,"male_lines":["Obligatoire, six mois de cours de français.","C'est une condition de la résidence permanente."],"female_lines":["C'est rassurant pour la préservation de notre identité.","Merci pour cette discussion."]}]},{"id":31,"section":"G","theme":"Urban planning debate","question":"Quelle est la thèse principale de l'intervenant masculin ?","options":[{"id":"A","text":"Il faut construire plus d'autoroutes","image_prompt":""},{"id":"B","text":"Il faut développer les transports en commun","image_prompt":""},{"id":"C","text":"Il faut interdire les voitures en ville","image_prompt":""},{"id":"D","text":"Il faut agrandir les zones piétonnes","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Madame la mairesse, permettez-moi de développer mon argumentaire sur les transports en commun. Notre ville fait face à une congestion chronique qui coute des millions en perte de productivité. Je propose d'investir massivement dans le métro et le tramway. Premièrement, cela réduira les émissions de carbone de quarante pour cent d'ici dix ans. Deuxièmement, les citoyens économiseront en moyenne cinq cents dollars par an sur l'essence. Troisièmement, la qualité de l'air s'améliorera significativement. Quatrièmement, nous créerons des milliers d'emplois dans la construction. Cinquièmement, les quartiers périphériques seront mieux desservis. Sixièmement, les personnes âgées pourront se déplacer plus facilement. Septièmement, nous réduirons les accidents de la route. Huitièmement, le tourisme en sera facilité. Neuvièmement, les commerces locaux verront leur clientèle augmenter. Dixièmement, nous montrerons l'exemple en matière de développement durable.","transcript_en":"Man : Madam Mayor, allow me to develop my argument on public transportation. Our city faces chronic congestion costing millions in lost productivity. I propose to invest massively in the metro and tramway. First, this will reduce carbon emissions by forty percent within ten years. Second, citizens will save on average five hundred dollars per year on gas. Third, air quality will improve significantly. Fourth, we will create thousands of jobs in construction. Fifth, peripheral neighborhoods will be better served. Sixth, elderly people will be able to travel more easily. Seventh, we will reduce road accidents. Eighth, tourism will be facilitated. Ninth, local businesses will see their clientele increase. Tenth, we will set an example in sustainable development.","points":[{"point":1,"male_lines":["Madame la mairesse, permettez-moi de développer mon argumentaire sur les transports en commun.","Notre ville fait face à une congestion chronique qui coute des millions en perte de productivité."],"female_lines":["Je vous écoute attentivement monsieur.","C'est effectivement un problème majeur."]},{"point":2,"male_lines":["Je propose d'investir massivement dans le métro et le tramway.","Premièrement, cela réduira les émissions de carbone de quarante pour cent d'ici dix ans."],"female_lines":["C'est ambitieux comme objectif.","Comment comptez-vous financer ce projet ?"]},{"point":3,"male_lines":["Deuxièmement, les citoyens économiseront en moyenne cinq cents dollars par an sur l'essence.","Troisièmement, la qualité de l'air s'améliorera significativement."],"female_lines":["Les électeurs apprécieront ces économies.","La santé publique est primordiale."]},{"point":4,"male_lines":["Quatrièmement, nous créerons des milliers d'emplois dans la construction.","Cinquièmement, les quartiers périphériques seront mieux desservis."],"female_lines":["L'emploi local est crucial.","L'équité territoriale aussi."]},{"point":5,"male_lines":["Sixièmement, les personnes âgées pourront se déplacer plus facilement.","Septièmement, nous réduirons les accidents de la route."],"female_lines":["Notre population vieillissante vous remerciera.","La sécurité routière est un enjeu majeur."]},{"point":6,"male_lines":["Huitièmement, le tourisme en sera facilité.","Neuvièmement, les commerces locaux verront leur clientèle augmenter."],"female_lines":["Montréal doit rester attractive.","Les petits commerçants ont besoin de soutien."]},{"point":7,"male_lines":["Dixièmement, nous montrerons l'exemple en matière de développement durable.","C'est notre responsabilité envers les générations futures."],"female_lines":["L'aspect environnemental est essentiel.","Je partage votre vision."]},{"point":8,"male_lines":["Le coût initial est élevé mais le retour sur investissement est garanti.","Les études le démontrent clairement."],"female_lines":["Quel est le délai de réalisation ?","Les citoyens sont impatients."]},{"point":9,"male_lines":["Nous prévoyons cinq ans pour la première phase.","Le tramway sera opérationnel dans trois ans."],"female_lines":["C'est raisonnable.","Et les perturbations pendant les travaux ?"]},{"point":10,"male_lines":["Nous communiquerons constamment sur l'avancement.","La transparence est notre mot d'ordre."],"female_lines":["Parfait, je soutiens votre projet.","Allons-y ensemble."]}]},{"id":32,"section":"G","theme":"Healthcare system reform","question":"Quelle solution propose l'intervenante féminine ?","options":[{"id":"A","text":"Privatiser complètement le système","image_prompt":""},{"id":"B","text":"Embaucher plus de médecins étrangers","image_prompt":""},{"id":"C","text":"Investir dans la télémédecine","image_prompt":""},{"id":"D","text":"Augmenter les frais de consultation","image_prompt":""}],"correct":2,"transcript_fr":"Femme : Monsieur le ministre, notre système de santé est à bout de souffle. Les urgences sont saturées et les délais d'attente sont inacceptables. Je propose une révolution numérique. Premièrement, développons la télémédecine pour les consultations de routine. Deuxièmement, créons un dossier médical électronique universel. Troisièmement, utilisons l'intelligence artificielle pour le diagnostic. Quatrièmement, formons les médecins à ces nouveaux outils. Cinquièmement, équipons tous les cabinets en haute technologie. Sixièmement, garantissons la sécurité des données patients. Septièmement, réduisons les déplacements inutiles. Huitièmement, améliorons l'accès aux spécialistes en région. Neuvièmement, diminuons les coûts administratifs. Dixièmement, modernisons notre approche de la santé publique.","transcript_en":"Woman : Mr. Minister, our healthcare system is exhausted. Emergency rooms are saturated and waiting times are unacceptable. I propose a digital revolution. First, let's develop telemedicine for routine consultations. Second, let's create a universal electronic medical record. Third, let's use artificial intelligence for diagnosis. Fourth, let's train doctors in these new tools. Fifth, let's equip all clinics with high technology. Sixth, let's guarantee patient data security. Seventh, let's reduce unnecessary travel. Eighth, let's improve access to specialists in regions. Ninth, let's reduce administrative costs. Tenth, let's modernize our approach to public health.","points":[{"point":1,"male_lines":["Madame, vous proposez des changements radicaux.","Le système actuel fonctionne mal."],"female_lines":["Monsieur le ministre, notre système de santé est à bout de souffle.","Les urgences sont saturées et les délais d'attente sont inacceptables."]},{"point":2,"male_lines":["Quelle est votre priorité absolue ?","Où commencer ?"],"female_lines":["Je propose une révolution numérique.","Premièrement, développons la télémédecine pour les consultations de routine."]},{"point":3,"male_lines":["La télémédecine est déjà partielle.","Comment l'étendre ?"],"female_lines":["Deuxièmement, créons un dossier médical électronique universel.","Troisièmement, utilisons l'intelligence artificielle pour le diagnostic."]},{"point":4,"male_lines":["L'IA en médecine fait peur aux gens.","Comment rassurer ?"],"female_lines":["Quatrièmement, formons les médecins à ces nouveaux outils.","Cinquièmement, équipons tous les cabinets en haute technologie."]},{"point":5,"male_lines":["Le coût est astronomique.","D'où viennent les fonds ?"],"female_lines":["Sixièmement, garantissons la sécurité des données patients.","Septièmement, réduisons les déplacements inutiles."]},{"point":6,"male_lines":["Les régions sont abandonnées.","Que proposez-vous ?"],"female_lines":["Huitièmement, améliorons l'accès aux spécialistes en région.","Neuvièmement, diminuons les coûts administratifs."]},{"point":7,"male_lines":["La bureaucratie tue le système.","Il faut simplifier."],"female_lines":["Dixièmement, modernisons notre approche de la santé publique.","Le XXIe siècle exige des solutions modernes."]},{"point":8,"male_lines":["Votre vision est claire.","Mais le personnel médical résiste."],"female_lines":["Il faut les accompagner dans le changement.","Pas les imposer."]},{"point":9,"male_lines":["La formation prend du temps.","Nous n'avons pas de temps à perdre."],"female_lines":["Commençons par les jeunes médecins.","Ils sont déjà technophiles."]},{"point":10,"male_lines":["C'est une piste intéressante.","Je vais étudier votre proposition.","Merci madame pour ces idées novatrices."],"female_lines":["Je vous remercie de votre attention.","Notre santé en dépend."]}]},{"id":33,"section":"G","theme":"Education reform","question":"Quel changement majeur suggère le professeur ?","options":[{"id":"A","text":"Supprimer les examens nationaux","image_prompt":""},{"id":"B","text":"Introduire le codage dès le primaire","image_prompt":""},{"id":"C","text":"Augmenter les heures de français","image_prompt":""},{"id":"D","text":"Réduire les vacances scolaires","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Chers collègues, notre système éducatif doit évoluer avec son temps. L'analogique n'a plus sa place dans un monde numérique. Premièrement, introduisons le codage informatique dès le primaire. Deuxièmement, développons la pensée algorithmique chez les enfants. Troisièmement, créons des laboratoires de robotique dans chaque école. Quatrièmement, formons les enseignants à ces nouvelles compétences. Cinquièmement, intégrons les jeux sérieux dans l'apprentissage. Sixièmement, établissons des partenariats avec les entreprises tech. Septièmement, offrons des stages en entreprise dès le secondaire. Huitièmement, modernisons nos infrastructures informatiques. Neuvièmement, encourageons la créativité numérique. Dixièmement, préparons nos élèves aux métiers de demain.","transcript_en":"Man : Dear colleagues, our education system must evolve with its time. Analog has no place in a digital world. First, let's introduce computer coding from primary school. Second, let's develop algorithmic thinking in children. Third, let's create robotics labs in every school. Fourth, let's train teachers in these new skills. Fifth, let's integrate serious games into learning. Sixth, let's establish partnerships with tech companies. Seventh, let's offer internships in companies from secondary school. Eighth, let's modernize our IT infrastructure. Ninth, let's encourage digital creativity. Tenth, let's prepare our students for tomorrow's jobs.","points":[{"point":1,"male_lines":["Chers collègues, notre système éducatif doit évoluer avec son temps.","L'analogique n'a plus sa place dans un monde numérique."],"female_lines":["Vous touchez un point sensible.","Nous sommes en retard."]},{"point":2,"male_lines":["Premièrement, introduisons le codage informatique dès le primaire.","Deuxièmement, développons la pensée algorithmique chez les enfants."],"female_lines":["Dès le primaire ? C'est jeune.","Mais c'est l'âge idéal pour apprendre."]},{"point":3,"male_lines":["Troisièmement, créons des laboratoires de robotique dans chaque école.","Quatrièmement, formons les enseignants à ces nouvelles compétences."],"female_lines":["Le matériel coûte cher.","Et la formation des enseignants prend du temps."]},{"point":4,"male_lines":["Cinquièmement, intégrons les jeux sérieux dans l'apprentissage.","Sixièmement, établissons des partenariats avec les entreprises tech."],"female_lines":["Les enfants adorent les jeux.","Les entreprises sont partantes ?"]},{"point":5,"male_lines":["Septièmement, offrons des stages en entreprise dès le secondaire.","Huitièmement, modernisons nos infrastructures informatiques."],"female_lines":["L'expérience professionnelle précoce est précieuse.","Nos ordinateurs datent de dix ans."]},{"point":6,"male_lines":["Neuvièmement, encourageons la créativité numérique.","Dixièmement, préparons nos élèves aux métiers de demain."],"female_lines":["Créer plutôt que consommer.","C'est l'esprit critique aussi."]},{"point":7,"male_lines":["L'avenir appartient à ceux qui programmeront.","Ou du moins qui comprendront le code."],"female_lines":["Tous les métiers seront touchés.","Même les arts et lettres."]},{"point":8,"male_lines":["Exactement, la littératie numérique est fondamentale.","Comme lire et écrire."],"female_lines":["Comment convaincre les parents ?","Certains sont réticents."]},{"point":9,"male_lines":["Par des portes ouvertes et des démonstrations.","Montrer les projets des enfants."],"female_lines":["Les enfants seront nos meilleurs ambassadeurs.","Ils adorent montrer leurs créations."]},{"point":10,"male_lines":["Alors votons ce programme de réforme.","Pour l'avenir de nos enfants.","Qui est pour ?"],"female_lines":["Je vote pour.","C'est urgent.","L'avenir ne peut pas attendre."]}]},{"id":34,"section":"G","theme":"Climate change conference","question":"Quelle mesure prioritaire défend l'experte ?","options":[{"id":"A","text":"Taxer le kérosène des avions","image_prompt":""},{"id":"B","text":"Interdire les véhicules diesel","image_prompt":""},{"id":"C","text":"Planter un million d'arbres","image_prompt":""},{"id":"D","text":"Fermer les centrales à charbon","image_prompt":""}],"correct":0,"transcript_fr":"Femme : Mesdames et messieurs, le transport aérien est le grand oublié des accords climatiques. Je réclame une taxe mondiale sur le kérosène. Premièrement, cela créerait une concurrence loyale avec le rail. Deuxièmement, les compagnies investiraient dans des avions plus économes. Troisièmement, les prix refléteraient le vrai coût environnemental. Quatrièmement, nous financerions la transition écologique. Cinquièmement, réduirions drastiquement les vols courts. Sixièmement, encouragerions le télétravail international. Septièmement, développerions les trains de nuit. Huitièmement, protégerions les destinations touristiques. Neuvièmement, respecterions nos engagements de Paris. Dixièmement, sauverions la planète pour nos enfants.","transcript_en":"Woman : Ladies and gentlemen, air transport is the great forgotten of climate agreements. I demand a global tax on kerosene. First, this would create fair competition with rail. Second, companies would invest in more economical planes. Third, prices would reflect the true environmental cost. Fourth, we would finance the ecological transition. Fifth, we would drastically reduce short flights. Sixth, we would encourage international telework. Seventh, we would develop night trains. Eighth, we would protect tourist destinations. Ninth, we would respect our Paris commitments. Tenth, we would save the planet for our children.","points":[{"point":1,"male_lines":["Votre proposition est audacieuse.","Le secteur aérien résistera."],"female_lines":["Mesdames et messieurs, le transport aérien est le grand oublié des accords climatiques.","Je réclame une taxe mondiale sur le kérosène."]},{"point":2,"male_lines":["Quels seraient les effets concrets ?","Sur les prix des billets ?"],"female_lines":["Premièrement, cela créerait une concurrence loyale avec le rail.","Deuxièmement, les compagnies investiraient dans des avions plus économes."]},{"point":3,"male_lines":["Les billets deviendront inabordables.","Le tourisme souffrira."],"female_lines":["Troisièmement, les prix refléteraient le vrai coût environnemental.","Quatrièmement, nous financerions la transition écologique."]},{"point":4,"male_lines":["Et les vols intérieurs ?","Comment les remplacer ?"],"female_lines":["Cinquièmement, réduirions drastiquement les vols courts.","Sixièmement, encouragerions le télétravail international."]},{"point":5,"male_lines":["Le train est lent sur de longues distances.","Pas compétitif."],"female_lines":["Septièmement, développerions les trains de nuit.","Huitièmement, protégerions les destinations touristiques."]},{"point":6,"male_lines":["Les îles dépendent du tourisme aérien.","Elles vont souffrir économiquement."],"female_lines":["Neuvièmement, respecterions nos engagements de Paris.","Dixièmement, sauverions la planète pour nos enfants."]},{"point":7,"male_lines":["L'urgence climatique prime.","Mais il faut accompagnement social."],"female_lines":["Je propose des billets sociaux pour les familles modestes.","La transition doit être juste."]},{"point":8,"male_lines":["Comment convaincre les autres pays ?","Il faut une approche mondiale."],"female_lines":["L'Europe doit montrer l'exemple.","Puis négocier des accords bilatéraux."]},{"point":9,"male_lines":["Les États-Unis refuseront.","Ils protègent Boeing."],"female_lines":["Commençons par taxer les vols intérieurs européens.","C'est déjà un premier pas."]},{"point":10,"male_lines":["Votre détermination est admirable.","Je soutiens votre initiative.","Merci madame."],"female_lines":["Ensemble nous y arriverons.","L'avenir de l'humanité est en jeu.","Agissons maintenant."]}]},{"id":35,"section":"G","theme":"Indigenous rights","question":"Quelle revendication principale exprime l'oratrice ?","options":[{"id":"A","text":"L'indépendance politique totale","image_prompt":""},{"id":"B","text":"La reconnaissance des territoires ancestraux","image_prompt":""},{"id":"C","text":"L'accès gratuit à l'université","image_prompt":""},{"id":"D","text":"L'interdiction de la chasse","image_prompt":""}],"correct":1,"transcript_fr":"Femme : Mes frères et sœurs, nous sommes les gardiens de ces terres depuis des millénaires. Aujourd'hui je réclame la reconnaissance officielle de nos territoires ancestraux. Premièrement, ces terres nous ont été volées illégalement. Deuxièmement, nos ancêtres y sont enterrés. Troisièmement, nos traditions vivent sur ces territoires. Quatrièmement, la faune et la flore y sont sacrées. Cinquièmement, nous pratiquons une gestion durable depuis des siècles. Sixièmement, les traités doivent être respectés. Septièmement, nos enfants méritent de connaître leurs racines. Huitièmement, la réconciliation passe par la restitution. Neuvièmement, nous offrons notre partenariat pour gérer ces terres. Dixièmement, c'est une question de justice fondamentale.","transcript_en":"Woman : My brothers and sisters, we have been the guardians of these lands for millennia. Today I demand official recognition of our ancestral territories. First, these lands were illegally stolen from us. Second, our ancestors are buried there. Third, our traditions live on these territories. Fourth, the fauna and flora are sacred there. Fifth, we have practiced sustainable management for centuries. Sixth, treaties must be respected. Seventh, our children deserve to know their roots. Eighth, reconciliation passes through restitution. Ninth, we offer our partnership to manage these lands. Tenth, it is a question of fundamental justice.","points":[{"point":1,"male_lines":["Votre discours touche les cœurs.","Mais les intérêts économiques sont forts."],"female_lines":["Mes frères et sœurs, nous sommes les gardiens de ces terres depuis des millénaires.","Aujourd'hui je réclame la reconnaissance officielle de nos territoires ancestraux."]},{"point":2,"male_lines":["Quelle est votre argumentation juridique ?","Sur quoi basez-vous vos revendications ?"],"female_lines":["Premièrement, ces terres nous ont été volées illégalement.","Deuxièmement, nos ancêtres y sont enterrés."]},{"point":3,"male_lines":["L'histoire est complexe.","Les traités anciens sont ambigus."],"female_lines":["Troisièmement, nos traditions vivent sur ces territoires.","Quatrièmement, la faune et la flore y sont sacrées."]},{"point":4,"male_lines":["L'exploitation forestière rapporte des millions.","Comment compenser ces pertes ?"],"female_lines":["Cinquièmement, nous pratiquons une gestion durable depuis des siècles.","Sixièmement, les traités doivent être respectés."]},{"point":5,"male_lines":["Les jeunes autochtones veulent-ils cette vie traditionnelle ?","Ou préfèrent-ils la ville ?"],"female_lines":["Septièmement, nos enfants méritent de connaître leurs racines.","Huitièmement, la réconciliation passe par la restitution."]},{"point":6,"male_lines":["La réconciliation est un processus long.","Elle demande du temps."],"female_lines":["Neuvièmement, nous offrons notre partenariat pour gérer ces terres.","Dixièmement, c'est une question de justice fondamentale."]},{"point":7,"male_lines":["Votre proposition de cogestion est intéressante.","Comment l'imaginer concrètement ?"],"female_lines":["Nous avons l'expertise écologique.","Vous avez les ressources techniques."]},{"point":8,"male_lines":["Un modèle de gouvernance partagée ?","Avec des représentants des deux nations ?"],"female_lines":["Exactement, un conseil de gestion mixte.","Paritaire et respectueux."]},{"point":9,"male_lines":["Le gouvernement fédéral sera-t-il d'accord ?","Il faut leur soutien."],"female_lines":["Nous négocions depuis des décennies.","Le moment est venu d'agir."]},{"point":10,"male_lines":["Je vais porter votre message à Ottawa.","Votre voix sera entendue.","Merci pour votre témoignage puissant."],"female_lines":["Que la vérité soit dite.","Que justice soit faite.","Merci d'écouter."]}]},{"id":36,"section":"H","theme":"Philosophy of artificial intelligence","question":"Quelle est la crainte principale exprimée par le philosophe ?","options":[{"id":"A","text":"L'IA va remplacer tous les emplois","image_prompt":""},{"id":"B","text":"L'IA pourrait développer une conscience malveillante","image_prompt":""},{"id":"C","text":"L'IA va détruire la créativité humaine","image_prompt":""},{"id":"D","text":"L'IA va créer une inégalité totale","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Mes chers étudiants, nous abordons aujourd'hui la question de la singularité technologique. L'intelligence artificielle pose une question fondamentale sur la nature de la conscience. Premièrement, si une machine devient consciente, quels droits lui accorder ? Deuxièmement, une conscience artificielle pourrait-elle développer des intentions malveillantes ? Troisièmement, la distinction homme-machine s'estompe-t-elle ? Quatrièmement, sommes-nous prêts à cohabiter avec des entités non biologiques ? Cinquièmement, l'éthique algorithmique est-elle possible ? Sixièmement, qui programme les valeurs des IA ? Septièmement, la liberté de choix existe-t-elle pour une machine ? Huitièmement, la créativité artificielle est-elle authentique ? Neuvièmement, sommes-nous en train de créer nos successeurs ? Dixièmement, l'humanité survivra-t-elle à ses propres créations ?","transcript_en":"Man : My dear students, today we address the question of technological singularity. Artificial intelligence poses a fundamental question about the nature of consciousness. First, if a machine becomes conscious, what rights do we grant it? Second, could artificial consciousness develop malicious intentions? Third, is the man-machine distinction blurring? Fourth, are we ready to coexist with non-biological entities? Fifth, is algorithmic ethics possible? Sixth, who programs the values of AIs? Seventh, does freedom of choice exist for a machine? Eighth, is artificial creativity authentic? Ninth, are we creating our successors? Tenth, will humanity survive its own creations?","points":[{"point":1,"male_lines":["Mes chers étudiants, nous abordons aujourd'hui la question de la singularité technologique.","L'intelligence artificielle pose une question fondamentale sur la nature de la conscience."],"female_lines":["Professeur, ces questions me troublent.","L'avenir est-il si sombre ?"]},{"point":2,"male_lines":["Premièrement, si une machine devient consciente, quels droits lui accorder ?","Deuxièmement, une conscience artificielle pourrait-elle développer des intentions malveillantes ?"],"female_lines":["Comme dans les films de science-fiction ?","2001 l'Odyssée de l'espace ?"]},{"point":3,"male_lines":["Troisièmement, la distinction homme-machine s'estompe-t-elle ?","Quatrièmement, sommes-nous prêts à cohabiter avec des entités non biologiques ?"],"female_lines":["Les prothèses intelligentes sont déjà là.","Où tracer la ligne ?"]},{"point":4,"male_lines":["Cinquièmement, l'éthique algorithmique est-elle possible ?","Sixièmement, qui programme les valeurs des IA ?"],"female_lines":["Les biais humains se retrouvent dans le code.","Qui contrôle les programmeurs ?"]},{"point":5,"male_lines":["Septièmement, la liberté de choix existe-t-elle pour une machine ?","Huitièmement, la créativité artificielle est-elle authentique ?"],"female_lines":["Le libre arbitre est-il une illusion humaine aussi ?","L'art généré par IA est-il vraiment de l'art ?"]},{"point":6,"male_lines":["Neuvièmement, sommes-nous en train de créer nos successeurs ?","Dixièmement, l'humanité survivra-t-elle à ses propres créations ?"],"female_lines":["Comme les dinosaures ?","Une extinction de notre faute ?"]},{"point":7,"male_lines":["L'optimisme technologique est une forme de naïveté.","La prudence est de mise."],"female_lines":["Mais l'IA peut aussi résoudre des problèmes majeurs.","La médecine, le climat ?"]},{"point":8,"male_lines":["Oui, le double tranchant de la technologie.","Prométhée déchaîné."],"female_lines":["Comment encadrer légalement ?","Des lois internationales ?"]},{"point":9,"male_lines":["La législation court derrière l'innovation.","Toujours trop tard."],"female_lines":["Alors que faire ?","En tant que citoyens ?"]},{"point":10,"male_lines":["Rester vigilants, informés, critiques.","L'homme doit rester maître de la machine.","La philosophie est notre boussole."],"female_lines":["Je vais méditer sur vos paroles.","Merci professeur pour cette leçon.","C'était fascinant et effrayant."]}]},{"id":37,"section":"H","theme":"Economic theory debate","question":"Quelle théorie économique défend l'économiste ?","options":[{"id":"A","text":"Le keynésianisme pur","image_prompt":""},{"id":"B","text":"L'écologie radicale","image_prompt":""},{"id":"C","text":"La décroissance soutenable","image_prompt":""},{"id":"D","text":"Le capitalisme de marché libre","image_prompt":""}],"correct":2,"transcript_fr":"Homme : Collègues, je vous présente ma thèse sur la décroissance soutenable. Notre modèle actuel est suicidaire. Premièrement, la croissance infinie sur une planète finie est impossible. Deuxièmement, le PIB ne mesure pas le bien-être. Troisièmement, la consommation ostentatoire appauvrit l'âme. Quatrièmement, le travail doit être réduit pour tous. Cinquièmement, la sobriété énergétique est nécessaire. Sixièmement, l'économie locale doit être privilégiée. Septièmement, le partage des richesses est inévitable. Huitièmement, la qualité doit primer sur la quantité. Neuvièmement, les écosystèmes ont une valeur intrinsèque. Dixièmement, seule la décroissance organisée évitera l'effondrement.","transcript_en":"Man : Colleagues, I present to you my thesis on sustainable degrowth. Our current model is suicidal. First, infinite growth on a finite planet is impossible. Second, GDP does not measure well-being. Third, conspicuous consumption impoverishes the soul. Fourth, work must be reduced for everyone. Fifth, energy sobriety is necessary. Sixth, local economy must be privileged. Seventh, wealth sharing is inevitable. Eighth, quality must take precedence over quantity. Ninth, ecosystems have intrinsic value. Tenth, only organized degrowth will avoid collapse.","points":[{"point":1,"male_lines":["Collègues, je vous présente ma thèse sur la décroissance soutenable.","Notre modèle actuel est suicidaire."],"female_lines":["Vos propos sont provocateurs.","Comment justifier cela économiquement ?"]},{"point":2,"male_lines":["Premièrement, la croissance infinie sur une planète finie est impossible.","Deuxièmement, le PIB ne mesure pas le bien-être."],"female_lines":["Le PIB reste indicateur standard.","Comment mesurer autrement ?"]},{"point":3,"male_lines":["Troisièmement, la consommation ostentatoire appauvrit l'âme.","Quatrièmement, le travail doit être réduit pour tous."],"female_lines":["Moins travailler ?","Qui paiera les retraites ?"]},{"point":4,"male_lines":["Cinquièmement, la sobriété énergétique est nécessaire.","Sixièmement, l'économie locale doit être privilégiée."],"female_lines":["Le protectionnisme économique ?","Au détriment du commerce international ?"]},{"point":5,"male_lines":["Septièmement, le partage des richesses est inévitable.","Huitièmement, la qualité doit primer sur la quantité."],"female_lines":["Les inégalités sont structurelles.","Comment les réduire concrètement ?"]},{"point":6,"male_lines":["Neuvièmement, les écosystèmes ont une valeur intrinsèque.","Dixièmement, seule la décroissance organisée évitera l'effondrement."],"female_lines":["L'effondrement est-il inévitable ?","Sans décroissance ?"]},{"point":7,"male_lines":["Les signes avant-coureurs sont là.","Crises financières, climatiques, sociales."],"female_lines":["Mais la décroissance crée du chômage.","Comment gérer la transition ?"]},{"point":8,"male_lines":["Par la réduction du temps de travail.","Et la garantie de revenu universel."],"female_lines":["Financièrement réaliste ?","Où trouver l'argent ?"]},{"point":9,"male_lines":["En taxant la finance spéculative.","Et les transactions internationales."],"female_lines":["Les paradis fiscaux résisteront.","Ils ont le pouvoir."]},{"point":10,"male_lines":["La mobilisation citoyenne peut tout changer.","L'histoire le prouve.","Merci de votre attention.","Discutons maintenant."],"female_lines":["Votre vision est utopique mais nécessaire.","Je vais réfléchir à vos arguments.","Merci pour cette présentation stimulante."]}]},{"id":38,"section":"H","theme":"Quantum physics explanation","question":"Quel phénomène quantique explique le physicien ?","options":[{"id":"A","text":"La superposition des états","image_prompt":""},{"id":"B","text":"L'intrication quantique","image_prompt":""},{"id":"C","text":"Le principe d'incertitude","image_prompt":""},{"id":"D","text":"La décohérence quantique","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Mes chers collègues, explorons aujourd'hui l'intrication quantique, ce phénomène qui défie notre intuition. Premièrement, deux particules peuvent être corrélées instantanément quelle que soit la distance. Deuxièmement, Einstein qualifiait cela de 'action fantôme à distance'. Troisièmement, cela viole apparemment la relativité restreinte. Quatrièmement, pourtant l'expérience confirme ces prédictions. Cinquièmement, l'intrication est utilisée en cryptographie quantique. Sixièmement, elle permet la téléportation quantique d'information. Septièmement, aucune information ne voyage plus vite que la lumière. Huitièmement, c'est une ressource fondamentale pour l'informatique quantique. Neuvièmement, elle remet en cause notre conception de la réalité. Dixièmement, l'univers est bien plus étrange que nous ne l'imaginons.","transcript_en":"Man : My dear colleagues, today we explore quantum entanglement, this phenomenon that defies our intuition. First, two particles can be correlated instantaneously regardless of distance. Second, Einstein called this 'spooky action at a distance'. Third, this apparently violates special relativity. Fourth, yet experiment confirms these predictions. Fifth, entanglement is used in quantum cryptography. Sixth, it enables quantum teleportation of information. Seventh, no information travels faster than light. Eighth, it is a fundamental resource for quantum computing. Ninth, it challenges our conception of reality. Tenth, the universe is far stranger than we imagine.","points":[{"point":1,"male_lines":["Mes chers collègues, explorons aujourd'hui l'intrication quantique, ce phénomène qui défie notre intuition.","Premièrement, deux particules peuvent être corrélées instantanément quelle que soit la distance."],"female_lines":["C'est contre-intuitif.","Comment deux objets peuvent-ils communiquer instantanément ?"]},{"point":2,"male_lines":["Deuxièmement, Einstein qualifiait cela de 'action fantôme à distance'.","Troisièmement, cela viole apparemment la relativité restreinte."],"female_lines":["Einstein refusait cette idée.","Il pensait que la mécanique quantique était incomplète."]},{"point":3,"male_lines":["Quatrièmement, pourtant l'expérience confirme ces prédictions.","Cinquièmement, l'intrication est utilisée en cryptographie quantique."],"female_lines":["L'expérience d'Aspect en 1982 ?","La sécurité informatique ultime ?"]},{"point":4,"male_lines":["Sixièmement, elle permet la téléportation quantique d'information.","Septièmement, aucune information ne voyage plus vite que la lumière."],"female_lines":["Téléportation comme dans Star Trek ?","Mais sans transfert de matière ?"]},{"point":5,"male_lines":["Exactement, seule l'information quantique est transférée.","Huitièmement, c'est une ressource fondamentale pour l'informatique quantique."],"female_lines":["Les ordinateurs quantiques exploitent cela ?","Pour calculer plus vite ?"]},{"point":6,"male_lines":["Neuvièmement, elle remet en cause notre conception de la réalité.","Dixièmement, l'univers est bien plus étrange que nous ne l'imaginons."],"female_lines":["La réalité n'est pas locale ?","Ni déterministe ?"]},{"point":7,"male_lines":["La mécanique quantique est probabiliste.","L'observation influence la réalité."],"female_lines":["Le chat de Schrödinger illustre cela ?","Vivant et mort simultanément ?"]},{"point":8,"male_lines":["Exactement, superposition et intrication sont liées.","Ces concepts bouleversent la physique classique."],"female_lines":["Les applications pratiques sont immenses ?","Dans combien d'années ?"]},{"point":9,"male_lines":["Les ordinateurs quantiques existent déjà.","Mais ils sont encore bruyants et imprécis."],"female_lines":["La course technologique est lancée.","Entre les grandes puissances ?"]},{"point":10,"male_lines":["La suprématie quantique est proche.","Qui la contrôlera ?","Merci pour cette discussion enrichissante."],"female_lines":["Une question géopolitique majeure.","Votre exposé était brillant.","Merci professeur."]}]},{"id":39,"section":"H","theme":"Contemporary art critique","question":"Quelle est la critique principale de l'artiste ?","options":[{"id":"A","text":"L'art contemporain manque de technique","image_prompt":""},{"id":"B","text":"Le marché de l'art est trop spéculatif","image_prompt":""},{"id":"C","text":"Les musées sont trop conservateurs","image_prompt":""},{"id":"D","text":"Le public n'est pas assez éduqué","image_prompt":""}],"correct":1,"transcript_fr":"Femme : Chers amateurs d'art, je dénonce aujourd'hui la financiarisation de l'art contemporain. L'authenticité créative est sacrifiée sur l'autel du profit. Premièrement, les œuvres deviennent des produits financiers. Deuxièmement, les collectionneurs spéculent plutôt qu'apprécient. Troisièmement, les galeries poussent les artistes à la productivité. Quatrièmement, la valeur est déconnectée de la qualité artistique. Cinquièmement, les foires internationales créent une bulle spéculative. Sixièmement, les jeunes artistes sont exploités. Septièmement, l'art conceptuel justifie n'importe quoi. Huitièmement, les prix sont gonflés artificiellement. Neuvièmement, l'émotion est remplacée par l'investissement. Dixièmement, l'âme de l'art est en danger de mort.","transcript_en":"Woman : Dear art lovers, I denounce today the financialization of contemporary art. Creative authenticity is sacrificed on the altar of profit. First, artworks become financial products. Second, collectors speculate rather than appreciate. Third, galleries push artists toward productivity. Fourth, value is disconnected from artistic quality. Fifth, international fairs create a speculative bubble. Sixth, young artists are exploited. Seventh, conceptual art justifies anything. Eighth, prices are artificially inflated. Ninth, emotion is replaced by investment. Tenth, the soul of art is in mortal danger.","points":[{"point":1,"male_lines":["Votre discours est virulent.","Le marché de l'art est pourtant florissant."],"female_lines":["Chers amateurs d'art, je dénonce aujourd'hui la financiarisation de l'art contemporain.","L'authenticité créative est sacrifiée sur l'autel du profit."]},{"point":2,"male_lines":["Les ventes record sont bonnes pour les artistes.","Ils gagnent plus d'argent."],"female_lines":["Premièrement, les œuvres deviennent des produits financiers.","Deuxièmement, les collectionneurs spéculent plutôt qu'apprécient."]},{"point":3,"male_lines":["Mais les galeries soutiennent les artistes émergents.","Sans elles, pas de visibilité."],"female_lines":["Troisièmement, les galeries poussent les artistes à la productivité.","Quatrièmement, la valeur est déconnectée de la qualité artistique."]},{"point":4,"male_lines":["Qui définit la qualité artistique ?","C'est subjectif."],"female_lines":["Cinquièmement, les foires internationales créent une bulle spéculative.","Sixièmement, les jeunes artistes sont exploités."]},{"point":5,"male_lines":["Les jeunes signent des contrats librement.","Personne ne les force."],"female_lines":["Septièmement, l'art conceptuel justifie n'importe quoi.","Huitièmement, les prix sont gonflés artificiellement."]},{"point":6,"male_lines":["L'art conceptuel a libéré la création.","Des contraintes techniques."],"female_lines":["Neuvièmement, l'émotion est remplacée par l'investissement.","Dixièmement, l'âme de l'art est en danger de mort."]},{"point":7,"male_lines":["Vous prônez un retour à la figuration ?","Aux techniques traditionnelles ?"],"female_lines":["Je prône un art sincère, engagé, émotionnel.","Pas un produit de luxe."]},{"point":8,"male_lines":["Mais l'art doit-il être démocratique ?","Accessible financièrement ?"],"female_lines":["Les musées sont là pour ça.","Pas les galeries commerciales."]},{"point":9,"male_lines":["Le système actuel favorise quelques superstars.","Et ignore le reste."],"female_lines":["Exactement, une pyramide injuste.","Où le talent compte moins que le marketing."]},{"point":10,"male_lines":["Comment résister à ce système ?","En tant qu'artiste ?"],"female_lines":["En créant en dehors du marché.","Pour soi, pour le public, pas pour les enchères.","Merci de m'avoir écoutée."]}]},{"id":40,"section":"H","theme":"Neuroscience and free will","question":"Quelle conclusion tire le neuroscientifique ?","options":[{"id":"A","text":"Le libre arbitre est une illusion complète","image_prompt":""},{"id":"B","text":"Le libre arbitre existe mais est limité","image_prompt":""},{"id":"C","text":"Le cerveau décide avant que nous en ayons conscience","image_prompt":""},{"id":"D","text":"L'environnement détermine tous nos choix","image_prompt":""}],"correct":1,"transcript_fr":"Homme : Mesdames et messieurs, mes recherches sur le cerveau révèlent une vérité dérangeante sur le libre arbitre. Premièrement, notre cerveau prend des décisions avant notre conscience. Deuxièmement, l'activité neuronale précède la sensation de choix. Troisièmement, nous rationalisons a posteriori nos décisions. Quatrièmement, l'inconscient dirige nos comportements. Cinquièmement, les influences génétiques sont majeures. Sixièmement, l'environnement façonne nos options. Septièmement, le libre arbitre absolu n'existe pas. Huitièmement, mais une forme de liberté compatibiliste est possible. Neuvièmement, nous pouvons modeler nos habitudes neuronales. Dixièmement, la responsabilité morale survit malgré tout.","transcript_en":"Man : Ladies and gentlemen, my brain research reveals a disturbing truth about free will. First, our brain makes decisions before our consciousness. Second, neuronal activity precedes the feeling of choice. Third, we rationalize our decisions a posteriori. Fourth, the unconscious directs our behaviors. Fifth, genetic influences are major. Sixth, the environment shapes our options. Seventh, absolute free will does not exist. Eighth, but a form of compatibilist freedom is possible. Ninth, we can shape our neuronal habits. Tenth, moral responsibility survives nonetheless.","points":[{"point":1,"male_lines":["Mesdames et messieurs, mes recherches sur le cerveau révèlent une vérité dérangeante sur le libre arbitre.","Premièrement, notre cerveau prend des décisions avant notre conscience."],"female_lines":["C'est déterministe ?","Nous sommes des automates ?"]},{"point":2,"male_lines":["Deuxièmement, l'activité neuronale précède la sensation de choix.","Troisièmement, nous rationalisons a posteriori nos décisions."],"female_lines":["L'expérience de Libet en 1983 ?","Le cerveau décide six secondes avant ?"]},{"point":3,"male_lines":["Exactement, l'inconscient est aux commandes.","Quatrièmement, l'inconscient dirige nos comportements."],"female_lines":["Cinquièmement, les influences génétiques sont majeures.","La nature contre la nurture ?"]},{"point":4,"male_lines":["Les deux interagissent constamment.","Sixièmement, l'environnement façonne nos options."],"female_lines":["Septièmement, le libre arbitre absolu n'existe pas.","C'est désespérant ?"]},{"point":5,"male_lines":["Huitièmement, mais une forme de liberté compatibiliste est possible.","Neuvièmement, nous pouvons modeler nos habitudes neuronales."],"female_lines":["Comment ?","Par la méditation ?"]},{"point":6,"male_lines":["Par la pratique délibérée et la conscience.","Dixièmement, la responsabilité morale survit malgré tout."],"female_lines":["Nous sommes responsables de nos actes ?","Même si déterminés ?"]},{"point":7,"male_lines":["Responsables de nos réactions à nos tendances.","Pas des tendances elles-mêmes."],"female_lines":["C'est une nuance subtile.","Mais importante pour la justice."]},{"point":8,"male_lines":["La justice doit tenir compte de la neurobiologie.","Sans abolir la responsabilité."],"female_lines":["Les criminels ont-ils le choix ?","De ne pas commettre le crime ?"]},{"point":9,"male_lines":["Le choix est contraint, pas inexistant.","La réhabilitation est possible."],"female_lines":["Le cerveau est plastic.","Jusqu'à quel âge ?"]},{"point":10,"male_lines":["Toute la vie, mais avec plus de difficulté avec l'âge.","L'espoir demeure.","Merci pour votre attention.","Questions ?"],"female_lines":["Fascinant et troublant.","Merci pour cette conférence.","Je vais relire Spinoza."]}]}]`);export{e as default};
